document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("contact-form");if(!e)return;const t=e.querySelector(".btn-send"),a=document.getElementById("contact-success");e.addEventListener("submit",async function(c){c.preventDefault();const n=document.getElementById("contact-email").value.trim(),o=document.getElementById("contact-message").value.trim();if(!n||!isValidEmail(n)){showToast(i18n.t("contact.form_error_email"),"error");return}if(!o){showToast(i18n.t("contact.form_error_message"),"error");return}const r={firstname:document.getElementById("contact-firstname").value.trim(),lastname:document.getElementById("contact-lastname").value.trim(),email:n,subject:document.getElementById("contact-subject").value,message:o},i=t.innerHTML;t.disabled=!0,t.innerHTML='<i class="fas fa-circle-notch fa-spin"></i> <span>'+i18n.t("contact.form_sending")+"</span>";try{const s=await fetch("/api/contact",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(r)});if(s.ok)a.classList.add("visible"),e.reset(),showToast(i18n.t("contact.form_success"),"success");else if(s.status===429){const m=await s.json().catch(()=>({}));showToast(m.message||i18n.t("login.too_many_attempts"),"error")}else showToast(i18n.t("contact.form_error_send"),"error")}catch{showToast(i18n.t("contact.form_error_send"),"error")}finally{t.disabled=!1,t.innerHTML=i}})});
